USE [_MORPHEUS_ENGINE_] -- DB CONNECTION
GO

--UTILIZADORES
--QUERY PARA LISTAR OS ADMINISTRADORES (TÊM DIREITOS TOTAIS DE EDIÇÃO E GESTÃO DA BD) DA PLATAFORMA
SELECT USER_ID, USER_FIRST_NAME, USER_LAST_NAME, USER_EMAIL, USER_PHONENUMBER, USER_PROFILE_PICTURE_PATH, USER_BIRTHDATE, USER_GENDER_NAME, COUNTRY_NAME, USER_ADRESS, USER_JOB_NAME, USER_ACADEMIC_LEVEL_NAME, USER_LEVEL_NAME FROM VW_USER_CARACTERISTICS (NOLOCK) WHERE USER_LEVEL_NAME = 'ADMINISTRATOR'
--QUERY PARA LISTAR OS PROGRAMADORES (TÊM DIREITOS RESTRITOS DE EDIÇÃO DA BASE DE DADOS => NÃO TÊM PERMISSÃO PARA ALTERAR AS PERMISSÕES DE OUTROS USERS, NEM PODEM REMOVER A BD) DA PLATAFORMA
SELECT USER_ID, USER_FIRST_NAME, USER_LAST_NAME, USER_EMAIL, USER_PHONENUMBER, USER_PROFILE_PICTURE_PATH, USER_BIRTHDATE, USER_GENDER_NAME, COUNTRY_NAME, USER_ADRESS, USER_JOB_NAME, USER_ACADEMIC_LEVEL_NAME, USER_LEVEL_NAME FROM VW_USER_CARACTERISTICS (NOLOCK) WHERE USER_LEVEL_NAME = 'DEVELOPERS'
--QUERY PARA LISTAR OS ANALISTAS DE DADOS (TÊM DIREITOS TOTAIS DE VISUALIZAÇÃO DE DADOS, EXCETO INFORMAÇÃO SENESIVEL - EX: PASSWORDS) DA PLATAFORMA
SELECT USER_ID, USER_FIRST_NAME, USER_LAST_NAME, USER_EMAIL, USER_PHONENUMBER, USER_PROFILE_PICTURE_PATH, USER_BIRTHDATE, USER_GENDER_NAME, COUNTRY_NAME, USER_ADRESS, USER_JOB_NAME, USER_ACADEMIC_LEVEL_NAME, USER_LEVEL_NAME FROM VW_USER_CARACTERISTICS (NOLOCK) WHERE USER_LEVEL_NAME = 'DATA_ANALYST'
--QUERY PARA LISTAR OS UTILIZADORES BASICOS (TÊM DIREITOS RESTRITOS DE VISUALIZAÇÃO DE DADOS) DA PLATAFORMA
SELECT USER_ID, USER_FIRST_NAME, USER_LAST_NAME, USER_EMAIL, USER_PHONENUMBER, USER_PROFILE_PICTURE_PATH, USER_BIRTHDATE, USER_GENDER_NAME, COUNTRY_NAME, USER_ADRESS, USER_JOB_NAME, USER_ACADEMIC_LEVEL_NAME, USER_LEVEL_NAME FROM VW_USER_CARACTERISTICS (NOLOCK) WHERE USER_LEVEL_NAME = 'USER'

--QUERY PARA LISTAR OS UTILIZADORES QUE SÃO CEO's DE ALGUMA EMPRESA
SELECT USER_ID, USER_FIRST_NAME, USER_LAST_NAME, USER_EMAIL, USER_PHONENUMBER, USER_PROFILE_PICTURE_PATH, USER_BIRTHDATE, USER_GENDER_NAME, COUNTRY_NAME, USER_ADRESS, USER_JOB_NAME, USER_ACADEMIC_LEVEL_NAME, USER_LEVEL_NAME, COMPANY_NAME, COMPANY_TYPES.COMPANY_TYPE_NAME FROM VW_USER_CARACTERISTICS INNER JOIN COMPANIES ON COMPANY_CEO_ID = USER_ID INNER JOIN COMPANY_TYPES ON COMPANIES.COMPANY_TYPE_ID = COMPANY_TYPES.COMPANY_TYPE_ID

--QUERY PARA LISTAR OS UTILIZADORES COM NIVEL ACADÉMICO SUPERIOR OU IGUAL AO MESTRADO (MASTER'S DEGREE)
SELECT USER_ID, USER_FIRST_NAME, USER_LAST_NAME, USER_EMAIL, USER_PHONENUMBER, USER_PROFILE_PICTURE_PATH, USER_BIRTHDATE, USER_GENDER_NAME, COUNTRY_NAME, USER_ADRESS, USER_JOB_NAME, USER_ACADEMIC_LEVEL_NAME, USER_LEVEL_NAME FROM VW_USER_CARACTERISTICS WHERE USER_ACADEMIC_LEVEL_ID >= 6;

--QUERY PARA CALCULAR A PERCENTAGEM DE UTILIZADORES COM NIVEL ACADÉMICO SUPERIOR OU IGUAL AO MESTRADO (MASTER'S DEGREE)
WITH SUBQUERY1 AS (SELECT COUNT(*) AS COUNT_USERS FROM VW_USER_CARACTERISTICS),
SUBQUERY2 AS (SELECT COUNT(*) AS COUNT_USERS_ABOVE_MASTERS FROM VW_USER_CARACTERISTICS WHERE USER_ACADEMIC_LEVEL_ID >= 6)
SELECT CAST(ROUND(dbo.FN_CALC_PERCENTAGE(SUBQUERY1.COUNT_USERS, SUBQUERY2.COUNT_USERS_ABOVE_MASTERS), 2) AS VARCHAR) + ' %' AS USERS_ABOVE_MASTERS_PERCENTAGE FROM SUBQUERY1 FULL JOIN SUBQUERY2 ON 1 = 1;

--QUERY PARA LISTAR
--ESTE SELECT LISTA OS DADOS DE CADA UTILIZADOR (DA VIEW 'VW_USER_CARACTERISTICS') ORDENADOS PELA DATA DE NASCIMENTO ASCENDENTEMENTE;
SELECT * FROM VW_USER_CARACTERISTICS (NOLOCK) ORDER BY USER_BIRTHDATE ASC;
GO

--ESTE SELECT LISTA OS DADOS DE CADA VEÍCULO (DA VIEW 'VW_SCIENTIFIC_PROSPECTION_DATA') ONDE O 'TASK_TYPE_NAME' É 'Atmospheric Research' E O 'VEHICLE_NAME' COMECA PELA LETRA 'A';
SELECT * FROM VW_SCIENTIFIC_PROSPECTION_DATA (NOLOCK) WHERE TASK_TYPE_NAME = 'Atmospheric Research' AND VEHICLE_NAME LIKE ('A%');
GO

--ESTE SELECT CONTÉM OS DADOS DE CADA MÁQUINA (DA VIEW 'MACHINES') ORDENADA PELO 'MACHINE_STATUS_NAME' DESCENDENTEMENTE, SENDO SOMENTE LISTADO O PRIMEIRO REGISTO;
SELECT TOP(1) * FROM VEHICLES (NOLOCK) ORDER BY VEHICLE_NAME DESC;
GO

--CITIES
--ESTE SELECT CALCULA A TAXA DE DESPERDICIO DE ENERGIA DE CADA CENTRAL, ORDENANDO OS VALORES POR ORDEM CRESCENTE DE TAXA DE DESPERDÍCIO.
WITH SUBQUERY1 AS (SELECT POWER_PLANT_ID, CONVERT(int, dbo.FN_CLAMP_FLOAT(CONVERT(float, dbo.FN_CALC_WASTED_ENERGY(dbo.FN_ENERGY_PRODUCTION_LAST_MONTH(POWER_PLANT_ID, MONTH(GETDATE())), dbo.FN_ENERGY_CONSUMPTION_LAST_MONTH(POWER_PLANT_ID, MONTH(GETDATE())), dbo.FN_ENERGY_STORAGE_LAST_MONTH(POWER_PLANT_ID, MONTH(GETDATE())))), 0, 1000000000)) AS WASTED_ENERGY FROM VW_POWER_FLUX_LOGS),
SUBQUERY2 AS (SELECT SUBQUERY1.POWER_PLANT_ID, dbo.FN_CALC_PERCENTAGE(dbo.FN_ENERGY_PRODUCTION_LAST_MONTH(SUBQUERY1.POWER_PLANT_ID, MONTH(GETDATE())), SUBQUERY1.WASTED_ENERGY) AS WASTED_ENERGY_RATE FROM SUBQUERY1)
SELECT SUBQUERY2.POWER_PLANT_ID, SUBQUERY2.WASTED_ENERGY_RATE FROM SUBQUERY2

SELECT TOP (20) * FROM VW_CITIES (NOLOCK) RIGHT JOIN VW_CITIES_ECONOMICAL_DATA (NOLOCK) ON VW_CITIES.CITY_ID = VW_CITIES_ECONOMICAL_DATA.CITY_ID WHERE (CITY_ECONOMICAL_DATA.CITY_AVERAGE_INCOME - CITY_ECONOMICAL_DATA.CITY_LIFE_COST) > 0 ORDER BY CITY_ECONOMICAL_DATA.CITY_GDP DESC;